#include <stdio.h>
#include <stdlib.h>
#include <assert.h>
#include <omp.h>

#include "common.h"

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

void lud_diagonal_omp(float *m, int matrix_dim, int offset)
{
  int i, j, k;
  float shadow[BLOCK_SIZE][BLOCK_SIZE];

  int array_offset = offset*matrix_dim+offset;
  for(i=0; BLOCK_SIZE > i; i++){
    for(k=0; k < BLOCK_SIZE; k++){
      shadow[i][k] = m[array_offset+k];
    }
    array_offset = array_offset + matrix_dim;
  }

  for(i=0; BLOCK_SIZE-1 > i; i++) {
    for(k=i+1; k < BLOCK_SIZE; k++){
      for(j=0; j < i; j++)
        shadow[k][i] -= shadow[k][j]*shadow[j][i];
      shadow[k][i] /= shadow[i][i];
    }

    for(k=0; k < BLOCK_SIZE; k++){
      for(j=0; j < i+1; j++)
        shadow[i+1][k] -= shadow[i+1][j]*shadow[j][k];
    }
  }

  array_offset = (offset+1)*matrix_dim+offset;
  for(i=1; BLOCK_SIZE > i; i++){
    for(k=0; k < BLOCK_SIZE; k++){
      m[array_offset+k] = shadow[i][k];
    }
    array_offset = array_offset + matrix_dim;
  }
}

void lud_perimeter_omp(float *m, int matrix_dim, int offset, int num_blocks)
{
  float dia[BLOCK_SIZE][BLOCK_SIZE];
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i, j, k, array_offset, idx, block;

  for(block=0; block < num_blocks; block++){
    for(idx=0; idx < BLOCK_SIZE; idx++){
      array_offset = offset*matrix_dim+offset;
      for(i=0; BLOCK_SIZE/2 > i; i++){
        dia[i][idx] = m[array_offset+idx];
        array_offset = array_offset + matrix_dim;
      }

      array_offset = offset*matrix_dim+offset;
      for(i=0; BLOCK_SIZE > i; i++){
        peri_row[i][idx] = m[array_offset+(block+1)*BLOCK_SIZE+idx];
        array_offset = array_offset + matrix_dim;
      }

      array_offset = (offset+BLOCK_SIZE/2)*matrix_dim+offset;
      for(i=BLOCK_SIZE/2; BLOCK_SIZE > i; i++){
        dia[i][idx] = m[array_offset+idx];
        array_offset = array_offset + matrix_dim;
      }

      array_offset = (offset+(block+1)*BLOCK_SIZE)*matrix_dim+offset;
      for(i=0; BLOCK_SIZE > i; i++){
        peri_col[idx][i] = m[array_offset+idx];
        array_offset = array_offset + matrix_dim;
      }
    }

    for(i=1; BLOCK_SIZE > i; i++){
      for(idx=0; idx < BLOCK_SIZE; idx++){
        for(j=0; j < i; j++)
          peri_row[i][idx] -= dia[i][j]*peri_row[j][idx];
      }
    }

    for(i=0; BLOCK_SIZE > i; i++){
      for(idx=0; idx < BLOCK_SIZE; idx++){
        for(j=0; j < i; j++)
          peri_col[idx][i] -= peri_col[idx][j]*dia[j][i];
        peri_col[idx][i] /= dia[i][i];
      }
    }

    for(idx=0; idx < BLOCK_SIZE; idx++){
      array_offset = (offset+1)*matrix_dim+offset;
      for(i=1; BLOCK_SIZE > i; i++){
        m[array_offset+(block+1)*BLOCK_SIZE+idx] = peri_row[i][idx];
        array_offset = array_offset + matrix_dim;
      }

      array_offset = (offset+(block+1)*BLOCK_SIZE)*matrix_dim+offset;
      for(i=0; BLOCK_SIZE > i; i++){
        m[array_offset+idx] = peri_col[i][idx];
        array_offset = array_offset + matrix_dim;
      }
    }
  }
}

void lud_internal_omp(float *m, int matrix_dim, int offset, int num_blocks)
{
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];
  int i, j, k, global_row_id, global_col_id;
  float sum;

  for(j=0; j < num_blocks; j++){
    for(i=0; i < num_blocks; i++){
      global_row_id = offset + (j+1)*BLOCK_SIZE;
      global_col_id = offset + (i+1)*BLOCK_SIZE;

      for(k=0; k < BLOCK_SIZE; k++){
        for(l=0; l < BLOCK_SIZE; l++){
          peri_row[k][l] = m[(offset+k)*matrix_dim+global_col_id+l];
          peri_col[k][l] = m[(global_row_id+k)*matrix_dim+offset+l];
        }
      }

      for(k=0; k < BLOCK_SIZE; k++){
        for(l=0; l < BLOCK_SIZE; l++){
          sum = 0;
          for(i=0; i < BLOCK_SIZE; i++)
            sum += peri_col[k][i] * peri_row[i][l];
          m[(global_row_id+k)*matrix_dim+global_col_id+l] -= sum;
        }
      }
    }
  }
}

void lud_omp(float *m, int matrix_dim)
{
  int i;

  for(i=0; matrix_dim-BLOCK_SIZE > i; i += BLOCK_SIZE){
    lud_diagonal_omp(m, matrix_dim, i);
    lud_perimeter_omp(m, matrix_dim, i, (matrix_dim-i)/BLOCK_SIZE-1);
    lud_internal_omp(m, matrix_dim, i, (matrix_dim-i)/BLOCK_SIZE-1);
  }
  lud_diagonal_omp(m, matrix_dim, i);
}
